#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int sx, sy, ex, ey; scanf("%d %d %d %d", &sx, &sy, &ex, &ey);
        int ans;
        if(sx==ex && sy==ey) ans = 0;
        else if(sx!=ex && sy!=ey) ans = 1;
        else ans = 2;
        printf("%d\n", ans);
    }
    return 0;
}

